function ft_print_alphabet():
  c = 'a'
  while c <= 'z':
    write(c)
    c = c + 1

hints.4_notausgang:
#include <unistd.h>
void ft_print_alphabet(void)
{
    char c;
    c = 'a';
    while (c <= 'z')
    {
        write(1, &c, 1);
        c++;
    }
}

